" --- Jenkins Declarative Pipeline (abap-pipeline.groovy) ---
pipeline {
    agent any
    environment {
        ABAP_SYSTEM = 'DEV'
        GIT_REPO = 'https://git.company.com/sap/z-sales.git'
        GIT_BRANCH = 'feature/*'
    }
    stages {
        stage('Checkout') {
            steps {
                checkout([$class: 'GitSCM',
                  branches: [[name: env.GIT_BRANCH]],
                  userRemoteConfigs: [[url: env.GIT_REPO]]])
            }
        }
        stage('Lint') {
            steps {
                script {
                    // Execute Code Inspector via RFC
                    sh "sap-ci abap-lint --system ${ABAP_SYSTEM} --package Z_SALES"
                }
            }
        }
        stage('Unit Test') {
            steps {
                script {
                    // Run ABAP Unit via SE80 batch
                    sh "sap-ci abap-unit --system ${ABAP_SYSTEM}"
                }
            }
        }
        stage('ATC Check') {
            steps {
                script {
                    sh "sap-ci atc-run --variant Z_QUALITY_GATE"
                }
            }
        }
        stage('Deploy') {
            steps {
                script {
                    // gCTS pull to QAS
                    sh "sap-ci gcts-pull --target QAS --branch main"
                }
            }
        }
        stage('Smoke Test') {
            steps {
                script {
                    sh "sap-ci smoke-test --system QAS --scenario order-lifecycle"
                }
            }
        }
    }
    post {
        failure {
            echo "Pipeline failed. Check ATC results and transport logs."
        }
    }
}

" --- GitHub Actions equivalent (abap-ci.yml) ---
name: ABAP CI Pipeline
on: [push]
jobs:
  build:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - name: Run ATC
        run: sap-ci atc-run --variant Z_QUALITY_GATE
      - name: Unit Tests
        run: sap-ci abap-unit --system DEV
      - name: Deploy
        run: sap-ci gcts-pull --target QAS --branch main
